import type { User } from "@supabase/supabase-js";

/**
 * Row from your public.user_roster table in Supabase.
 *
 * IMPORTANT: `uid` in this table is NOT the same as Supabase Auth's user.id
 * (auth.users.id). They are separate identifiers from different systems.
 * Profile lookup should use email (or another shared field), not auth user id.
 */
export type UserProfile = {
  id: number;
  created_at: string | null;
  uid: string | null;
  first_name: string | null;
  last_name: string | null;
  phone: string | null;
  email: string | null;
  cohort: number | null;
  status: string | null;
  app_role: string | null;
  program_role: string | null;
  fd_required: number | null;
  ss_required: number | null;
  mentee_count: number | null;
};

/**
 * Auth user + profile from public.user_roster. Use getCurrentUserWithProfile() to fetch.
 */
export type UserWithProfile = {
  user: User;
  profile: UserProfile | null;
};

/** app_role hierarchy (lowest to highest): null -> team_leader -> developer */
export const APP_ROLE_ORDER = [null, "team_leader", "developer"] as const;

export type AppRole = (typeof APP_ROLE_ORDER)[number];
